function active$FormPaymentTerm(f) {f.add_onResponseComplete(on$FormPaymentTerm$ResponseComplete);}
function close$FormPaymentTerm(f) {try {f.remove_onResponseComplete(on$FormPaymentTerm$ResponseComplete)} catch (ex) {}}
function on$FormPaymentTerm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_tt');
      break;
    default:
      break;
  }
}      

      &ScriptIrregular;
